import{_ as t,a as o,b as n,c as i}from"./chunks/Connected.KElPUq4_.js";import{_ as a,o as l,c as s,a3 as d}from"./chunks/framework.DXXx-gl1.js";const k=JSON.parse('{"title":"KdNet Remote Desktop","description":"","frontmatter":{},"headers":[],"relativePath":"WindowsDebug/KdNetRDP.md","filePath":"WindowsDebug/KdNetRDP.md","lastUpdated":1761392318000}'),r={name:"WindowsDebug/KdNetRDP.md"};function c(u,e,h,p,m,f){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="kdnet-remote-desktop" tabindex="-1">KdNet Remote Desktop <a class="header-anchor" href="#kdnet-remote-desktop" aria-label="Permalink to &quot;KdNet Remote Desktop&quot;">​</a></h1><blockquote><p>This method is intended for early-stage debugging. You can connect to the target device&#39;s Windows remote desktop via KdNet to test touch, USB, etc. References and tutorials adapted from the <a href="https://github.com/WOA-Project/" target="_blank" rel="noreferrer">WOA Project</a>.</p></blockquote><h2 id="preparation" tabindex="-1">Preparation <a class="header-anchor" href="#preparation" aria-label="Permalink to &quot;Preparation&quot;">​</a></h2><ul><li>A device that has just had Windows deployed and has not been booted yet.</li><li>The ESP partition&#39;s ESP FLAG must have been set correctly before deploying Windows.</li><li>The phone is currently in Mass Storage Mode and connected to the PC.</li><li>You have read the <a href="/DocumentWebsite/WindowsDebug/SetupKDNET.html">KDNET setup guide</a> and performed the full procedure at least once.</li><li>Download <code>unattend.xml</code> from <a href="/DocumentWebsite/WindowsDebug/KdNetRDP/unattend.xml">unattend.xml</a>.</li></ul><div class="warning custom-block"><p class="custom-block-title">Note</p><p>The unattended file only takes effect on the first boot. Make sure you have just finished deploying the system and installed drivers.</p><ul><li>For installing Windows see <a href="/DocumentWebsite/InstallationGuides/WindowsInstallation.html">Windows installation summary</a>.</li><li>For driver installation see <a href="/DocumentWebsite/InstallationGuides/InstallDrivers.html">Install Drivers</a>.</li></ul></div><h2 id="configure-unattended-setup" tabindex="-1">Configure Unattended Setup <a class="header-anchor" href="#configure-unattended-setup" aria-label="Permalink to &quot;Configure Unattended Setup&quot;">​</a></h2><ul><li>Open File Explorer and locate the system drive of the phone.</li><li>Enter <code>\\Windows\\Panther\\</code>.</li><li>Copy the <code>unattend.xml</code> you downloaded into this folder. <ul><li>Optional: you can modify the <code>LocalUser</code> in <code>unattend.xml</code> to change the created username.</li></ul></li><li>Eject the disk and reboot the phone, then boot into UEFI.</li><li>Wait for the system to boot. The normal flow is: <ul><li>Spinning wheel -&gt; Getting devices ready -&gt; Ready -&gt; Automatic reboot</li></ul></li><li>After the automatic reboot, boot UEFI again. The normal flow is: <ul><li>Spinning wheel -&gt; OOBE -&gt; Enter desktop as user <code>LocalUser</code></li></ul></li><li>Note both steps are automated; you only need to boot UEFI twice.</li><li>If on first boot you see a &quot;Windows could not complete the installation... click OK to restart&quot; message, check the ESP FLAG and reinstall Windows if necessary.</li></ul><h2 id="windbg-connection" tabindex="-1">Windbg Connection <a class="header-anchor" href="#windbg-connection" aria-label="Permalink to &quot;Windbg Connection&quot;">​</a></h2><ul><li>Follow the KDNET setup steps in <a href="/DocumentWebsite/WindowsDebug/SetupKDNET.html#setup-bcd">SetupKDNET</a> to configure KDNET and connect. <ul><li>If the debugger auto-breaks, click <code>Go</code> in the top-left of Windbg or type <code>g</code> and press Enter in the command line.</li></ul></li><li>After the phone boots into Windows, click the <code>Break</code> button in the top-left of Windbg. In the command line area enter <code>!process 0 1</code> and press Enter, then wait for the output to finish.</li><li>Pick any process, click the blue data link after <code>Peb</code>, Windbg will execute the command and dump a lot of data. <img src="'+t+'" alt="Process"></li><li>In the output find <code>USERDOMAIN</code> and copy the value after it. It is usually like <code>PHONE-XXXXX</code> or <code>DESKTOP-XXXX</code>. <img src="'+o+'" alt="UserDomain"></li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If the selected Peb output does not contain <code>USERDOMAIN</code>, try another process&#39;s Peb.</p></div><h2 id="rdp-connection" tabindex="-1">RDP Connection <a class="header-anchor" href="#rdp-connection" aria-label="Permalink to &quot;RDP Connection&quot;">​</a></h2><ul><li>Open the built-in Windows Remote Desktop tool (<code>Remote Desktop Connection</code>). You can search it in the Start menu or press <code>Win+R</code> and run <code>mstsc</code>.</li><li>Enter the <code>USERDOMAIN</code> you copied in the <code>Computer</code> field and click Connect. <img src="'+n+'" alt="Connect"></li><li>The username is <code>LocalUser</code>, or whatever you set in <code>unattend.xml</code>.</li><li>There is no password; enter the username and connect. If you are warned about a certificate, ignore/accept it.</li><li>If Remote Desktop connects successfully, the setup is complete — start your debugging session! <img src="'+i+'" alt="Connected"></li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://learn.microsoft.com/zh-cn/windows-hardware/manufacture/desktop/update-windows-settings-and-scripts-create-your-own-answer-file-sxs" target="_blank" rel="noreferrer">MSDN: Answer file (unattend.xml)</a></li></ul>',14)])])}const w=a(r,[["render",c]]);export{k as __pageData,w as default};
